window.PACTO.acts["reg-2018-1726"]={"label": "REGOLAMENTO (UE) 2018/1726 DEL PARLAMENTO EUROPEO E DEL CONSIGLIO", "short": "Reg. 2018/1726", "file": "ext-reg-2018-1726.html", "external": true, "version": "consolidato 2025-01-28", "eurlex": "https://eur-lex.europa.eu/eli/reg/2018/1726/oj/ita", "articles": {"1": {"label": "Articolo 1", "heading": "Oggetto", "anchor": "art_1", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">È istituita un’Agenzia dell’Unione europea per la gestione operativa dei sistemi IT su larga scala nello spazio di libertà, sicurezza e giustizia («Agenzia»).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’Agenzia istituita con il presente regolamento sostituisce e succede all’Agenzia europea per la gestione operativa dei sistemi IT su larga scala nello spazio di libertà, sicurezza e giustizia, istituita con il regolamento (UE) n. 1077/2011.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’Agenzia è responsabile della gestione operativa del sistema d’informazione Schengen (SIS II), del sistema d’informazione visti (VIS) e del sistema per il confronto delle impronte digitali Eurodac.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L'Agenzia è responsabile della preparazione, dello sviluppo o della gestione operativa del sistema di ingressi/uscite (EES), di DubliNet, del sistema europeo di informazione e autorizzazione ai viaggi (ETIAS), di ECRIS-TCN e dell'<span>\n<span class=\"boldface\">►C4</span>\n</span> implementazione di riferimento ECRIS<span class=\"boldface\"> ◄ </span>.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M4\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">L’Agenzia è responsabile dello sviluppo e della gestione operativa, compresi gli sviluppi tecnici, del sistema informatizzato per lo scambio elettronico transfrontaliero di dati nel settore della cooperazione giudiziaria in materia civile e penale (sistema «e-CODEX»).</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4 <span class=\"italics\">ter</span>.  </span>\n<div class=\"norm inline-element\">L’Agenzia è responsabile dello sviluppo e della gestione operativa, compresi gli sviluppi tecnici, della piattaforma di collaborazione per le squadre investigative comuni («piattaforma di collaborazione per le SIC»).</div>\n</div>"], [null, "<p class=\"modref\">\n▼M4\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">L’Agenzia può essere incaricata della preparazione, dello sviluppo o della gestione operativa di sistemi IT su larga scala nello spazio di libertà, sicurezza e giustizia diversi da quelli di cui ai paragrafi 3, 4 e 4 <span class=\"italics\">bis</span> del presente articolo, ivi compresi i sistemi esistenti, solo se così previsto dai pertinenti atti giuridici dell’Unione che disciplinano tali sistemi, sulla base degli articoli da 67 a 89 TFUE, tenendo conto, ove opportuno, degli sviluppi della ricerca di cui all’articolo 14 del presente regolamento e dei risultati dei progetti pilota e dei prototipi di cui all’articolo 15 del presente regolamento.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">La gestione operativa comprende tutti i compiti necessari per mantenere operativi i sistemi IT su larga scala conformemente alle disposizioni specifiche applicabili a ciascuno di essi, inclusa la responsabilità dell’infrastruttura di comunicazione da essi utilizzata. Tali sistemi IT su larga scala non si scambiano dati né consentono la condivisione di informazioni o di conoscenze, salvo se così previsto da uno specifico atto giuridico.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’Agenzia è inoltre incaricata dei compiti seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantire la qualità dei dati in conformità dell’articolo 12;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sviluppare le azioni necessarie per consentire l’interoperabilità in conformità dell’articolo 13;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">effettuare attività di ricerca in conformità dell’articolo 14;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">realizzare progetti pilota, prototipi e attività di collaudo in conformità dell’articolo 15;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">prestare sostegno agli Stati membri e alla Commissione in conformità dell’articolo 16.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "2": {"label": "Articolo 2", "heading": "Obiettivi", "anchor": "art_2", "frags": [[null, "<p class=\"norm\">Fatte salve le rispettive responsabilità della Commissione e degli Stati membri ai sensi degli atti giuridici dell’Unione che disciplinano i sistemi IT su larga scala, l’Agenzia garantisce:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo sviluppo di sistemi IT su larga scala utilizzando un’adeguata struttura di gestione di progetto per sviluppare efficacemente tali sistemi;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un esercizio efficace, sicuro e continuo dei sistemi IT su larga scala;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la gestione efficiente e finanziariamente responsabile dei sistemi IT su larga scala;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un servizio di qualità adeguatamente elevata per gli utenti dei sistemi IT su larga scala;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la continuità e un servizio ininterrotto;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un livello elevato di protezione dei dati conformemente alla legislazione dell’Unione in materia di protezione dei dati, comprese le disposizioni specifiche relative a ciascun sistema IT su larga scala;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un livello adeguato di sicurezza dei dati e materiale in conformità delle norme applicabili, comprese le disposizioni specifiche relative a ciascun sistema IT su larga scala.</p>\n</div>\n</div>"]]}, "3": {"label": "Articolo 3", "heading": "Compiti relativi al SIS II", "anchor": "art_3", "frags": [[null, "<p class=\"norm\">Con riguardo al SIS II, l’Agenzia svolge:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i compiti attribuiti all’organo di gestione dal regolamento (CE) n. 1987/2006 e dalla decisione 2007/533/GAI; e</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i compiti relativi alla formazione sull’uso tecnico del SIS II, destinata in particolare al personale SIRENE (SIRENE — informazioni supplementari richieste all’ingresso nazionale), e relativi alla formazione di esperti sugli aspetti tecnici del SIS II nel quadro della valutazione di Schengen.</p>\n</div>\n</div>"]]}, "4": {"label": "Articolo 4", "heading": "Compiti relativi al VIS", "anchor": "art_4", "frags": [[null, "<p class=\"norm\">Con riguardo al VIS, l’Agenzia svolge:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i compiti attribuiti all’organo di gestione dal regolamento (CE) n. 767/2008 e dalla decisione 2008/633/GAI; e</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i compiti relativi alla formazione sull’uso tecnico del VIS e alla formazione di esperti sugli aspetti tecnici del VIS nel quadro della valutazione di Schengen.</p>\n</div>\n</div>"]]}, "5": {"label": "Articolo 5", "heading": "Compiti relativi all’Eurodac", "anchor": "art_5", "frags": [[null, "<p class=\"norm\">Con riguardo all’Eurodac, l’Agenzia svolge:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i compiti attribuitile dal regolamento (UE) n. 603/2013; e</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i compiti relativi alla formazione sull’uso tecnico dell’Eurodac.</p>\n</div>\n</div>"]]}, "6": {"label": "Articolo 6", "heading": "Compiti relativi all’EES", "anchor": "art_6", "frags": [[null, "<p class=\"norm\">Con riguardo all’EES, l’Agenzia svolge:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i compiti attribuitile dal regolamento (UE) 2017/2226; e</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i compiti relativi alla formazione sull’uso tecnico dell’EES e alla formazione di esperti sugli aspetti tecnici dell’EES nel quadro della valutazione di Schengen.</p>\n</div>\n</div>"]]}, "7": {"label": "Articolo 7", "heading": "Compiti relativi all’ETIAS", "anchor": "art_7", "frags": [[null, "<p class=\"norm\">Con riguardo all’ETIAS, l’Agenzia svolge:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i compiti attribuitile dal regolamento (UE) 2018/1240; e</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i compiti relativi alla formazione sull’uso tecnico dell’ETIAS e alla formazione di esperti sugli aspetti tecnici dell’ETIAS nel quadro della valutazione di Schengen.</p>\n</div>\n</div>"]]}, "8": {"label": "Articolo 8", "heading": "Compiti relativi a DubliNet", "anchor": "art_8", "frags": [[null, "<p class=\"norm\">Con riguardo a DubliNet, l’Agenzia svolge:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la gestione operativa di DubliNet, un canale sicuro di trasmissione elettronica separato tra le autorità degli Stati membri, istituito in applicazione dell’articolo 18 del regolamento (CE) n. 1560/2003, ai fini degli articoli 31, 32 e 34 del regolamento (UE) n. 604/2013 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">1</span>\n); e</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i compiti relativi alla formazione sull’uso tecnico di DubliNet.</p>\n</div>\n</div>"]]}, "8a": {"label": "Articolo 8 bis", "heading": "Compiti relativi a ECRIS-TCN e all' ►C4 implementazione di riferimento ECRIS ◄", "anchor": "art_8a", "frags": [[null, "<p class=\"norm\">Con riguardo a ECRIS-TCN e all'<span>\n<span class=\"boldface\">►C4</span>\n</span> implementazione di riferimento ECRIS<span class=\"boldface\"> ◄ </span>, l'Agenzia svolge:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i compiti attribuiti all'Agenzia conformemente al regolamento (UE) 2019/816 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">2</span>\n);</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i compiti relativi alla formazione sull'uso tecnico di ECRIS-TCN e dell'<span>\n<span class=\"boldface\">►C4</span>\n</span> implementazione di riferimento ECRIS<span class=\"boldface\"> ◄ </span>.</p>\n</div>\n</div>"]]}, "8b": {"label": "Articolo 8 ter", "heading": "Compiti relativi al sistema e-CODEX", "anchor": "art_8b", "frags": [[null, "<p class=\"norm\">Con riguardo al sistema e-CODEX, l’Agenzia svolge:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i compiti attribuiti all’Agenzia conformemente al regolamento (UE) 2022/850 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">3</span>\n);</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i compiti relativi alla formazione sull’uso tecnico del sistema e-CODEX, compresa la fornitura di materiale didattico online.</p>\n</div>\n</div>"]]}, "8c": {"label": "Articolo 8 quater", "heading": "Compiti relativi alla piattaforma di collaborazione per le SIC", "anchor": "art_8c", "frags": [[null, "<p class=\"norm\">Con riguardo alla piattaforma di collaborazione per le SIC, l’Agenzia svolge:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i compiti attribuiti all’Agenzia conformemente al regolamento (UE) 2023/969 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">4</span>\n);</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i compiti relativi alla formazione sull’uso tecnico della piattaforma di collaborazione per le SIC fornita al segretariato della rete delle SIC, compresa la fornitura di materiale didattico.</p>\n</div>\n</div>"]]}, "8d": {"label": "Articolo 8 quinquies", "heading": "Compiti relativi al router Prüm II", "anchor": "art_8d", "frags": [[null, "<p class=\"norm\">Con riguardo al router Prüm II, l’Agenzia svolge i compiti relativi che le sono conferiti da tale regolamento (UE) 2024/982 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">5</span>\n).</p>"]]}, "9": {"label": "Articolo 9", "heading": "Compiti relativi allo sviluppo e alla gestione operativa di altri sistemi IT su larga scala", "anchor": "art_9", "frags": [[null, "<p class=\"norm\">Ove sia incaricata della preparazione, dello sviluppo o della gestione operativa di altri sistemi IT su larga scala di cui all’articolo 1, paragrafo 5, l’Agenzia svolge, secondo il caso, i compiti conferitile dall’atto giuridico dell’Unione che disciplina il pertinente sistema e i compiti relativi alla formazione sull’uso tecnico di tale sistema.</p>"]]}, "10": {"label": "Articolo 10", "heading": "Soluzioni tecniche che richiedono condizioni specifiche prima dell’attuazione", "anchor": "art_10", "frags": [[null, "<p class=\"norm\">Qualora gli atti giuridici dell’Unione che disciplinano i sistemi sotto la responsabilità dell’Agenzia impongano a quest’ultima di mantenere tali sistemi in funzione 24 ore su 24 e 7 giorni su 7 e senza compromettere tali atti giuridici dell’Unione, l’Agenzia implementa soluzioni tecniche al fine di soddisfare tali requisiti. Qualora tali soluzioni tecniche richiedano una duplicazione di un sistema o una duplicazione dei componenti di un sistema, esse sono attuate soltanto a seguito di una valutazione d’impatto e di un’analisi costi-benefici indipendenti commissionate dall’Agenzia e previa consultazione della Commissione e decisione favorevole del consiglio di amministrazione. La valutazione d’impatto esamina altresì le esigenze presenti e future in termini di capacità di accoglienza dei siti tecnici esistenti in relazione allo sviluppo di siffatte soluzioni tecniche, nonché gli eventuali rischi relativi all’attuale configurazione operativa.</p>"]]}, "11": {"label": "Articolo 11", "heading": "Compiti relativi all’infrastruttura di comunicazione", "anchor": "art_11", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’Agenzia svolge tutti i compiti relativi all’infrastruttura di comunicazione dei sistemi conferitile dagli atti giuridici dell’Unione che disciplinano i sistemi, ad eccezione del caso dei sistemi che per l’infrastruttura di comunicazione utilizzano EuroDomain. Nel caso dei sistemi che utilizzano in tal modo EuroDomain, la Commissione è responsabile dei compiti di esecuzione del bilancio, di acquisizione e di rinnovo e degli aspetti contrattuali. Conformemente agli atti giuridici dell’Unione che disciplinano i sistemi che utilizzano EuroDomain, i compiti relativi all’infrastruttura di comunicazione, compresi la gestione operativa e la sicurezza, devono essere suddivisi tra l’Agenzia e la Commissione. Per assicurare la coerenza tra l’esercizio delle loro rispettive responsabilità, tra l’agenzia e la Commissione sono conclusi accordi di lavoro operativi, rispecchiati in un memorandum d’intesa.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’infrastruttura di comunicazione è gestita e controllata adeguatamente in modo da proteggerla da minacce e da garantire la sua sicurezza e quella dei sistemi, compresa la sicurezza dei dati scambiati attraverso l’infrastruttura di comunicazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’Agenzia adotta misure adeguate, compresi piani di sicurezza, volte tra l’altro ad impedire, in particolare mediante tecniche appropriate di cifratura, che durante la trasmissione di dati personali o il trasporto dei supporti di dati, i dati personali possano essere letti, copiati, modificati o cancellati senza autorizzazione. Tutte le informazioni operative connesse al sistema circolano criptate nell’infrastruttura di comunicazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Compiti relativi alla realizzazione, all’installazione, alla manutenzione e al monitoraggio dell’infrastruttura di comunicazione possono essere affidati a soggetti o ad organismi esterni di diritto privato conformemente al regolamento (UE, Euratom) 2018/1046. Tali compiti sono svolti sotto la responsabilità e la stretta supervisione dell’Agenzia.</p>\n<p class=\"norm inline-element\">Nello svolgimento dei compiti di cui al primo comma, tutti i soggetti o gli organismi esterni di diritto privato, tra cui i gestori della rete, sono vincolati dalle misure di sicurezza di cui al paragrafo 3 e non hanno accesso in alcun modo ai dati operativi memorizzati nei sistemi o trasferiti mediante l’infrastruttura di comunicazione né allo scambio SIRENE relativo al SIS II.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">La gestione delle chiavi criptate rimane di competenza dell’Agenzia e non è esternalizzata ad alcun soggetto esterno di diritto privato. Sono fatti salvi i contratti esistenti sulle infrastrutture di comunicazione del SIS II, del VIS e dell’Eurodac.</div>\n</div>"]]}, "12": {"label": "Articolo 12", "heading": "Qualità dei dati", "anchor": "art_12", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Fatte salve le responsabilità degli Stati membri per quanto riguarda i dati inseriti nei sistemi sotto la responsabilità operativa dell'Agenzia, quest'ultima, in stretta collaborazione con i suoi gruppi consultivi, predispone, per tutti i sistemi di cui ha la responsabilità operativa, procedure e meccanismi automatizzati di controllo della qualità dei dati, indicatori comuni della qualità dei dati e norme minime di qualità per conservare i dati, in conformità degli strumenti giuridici che disciplinano tali sistemi di informazione e dell'articolo 37 dei regolamenti (UE) 2019/817 (\n<span class=\"superscript\">6</span>\n) e (UE) 2019/818 (\n<span class=\"superscript\">7</span>\n) del Parlamento europeo e del Consiglio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L'Agenzia istituisce un archivio centrale, contenente unicamente dati anonimizzati, di relazioni e statistiche a norma dell'articolo 39 dei regolamenti (UE) 2019/817 e (UE) 2019/818, fatte salve specifiche disposizioni contenute negli strumenti giuridici che disciplinano lo sviluppo, l'istituzione, il funzionamento e l'uso di tutti i sistemi IT su larga scala gestiti dall'Agenzia.</div>\n</div>"]]}, "13": {"label": "Articolo 13", "heading": "Interoperabilità", "anchor": "art_13", "frags": [[null, "<p class=\"norm\">Laddove l’interoperabilità dei sistemi IT su larga scala sia prevista da un pertinente atto giuridico dell’Unione, l’Agenzia sviluppa le azioni necessarie per consentire tale interoperabilità.</p>"]]}, "13a": {"label": "Articolo 13 bis", "heading": "Compiti relativi al router", "anchor": "art_13a", "frags": [[null, "<p class=\"norm\">Con riguardo ai regolamenti (UE) 2025/12 (\n<span class=\"superscript\">8</span>\n) e (UE) 2025/13 (\n<span class=\"superscript\">9</span>\n) del Parlamento europeo e del Consiglio, l’Agenzia svolge i compiti relativi al router che le sono conferiti da tali regolamenti.</p>"]]}, "14": {"label": "Articolo 14", "heading": "Monitoraggio della ricerca", "anchor": "art_14", "frags": [[null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’Agenzia segue gli sviluppi della ricerca per la gestione operativa del SIS II, del VIS, di Eurodac, dell’EES, dell’ETIAS, di DubliNet, di ECRIS-TCN, del sistema e-CODEX, della piattaforma di collaborazione per le SIC e di altri sistemi IT su larga scala di cui all’articolo 1, paragrafo 5.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’Agenzia può contribuire all’attuazione delle parti del programma quadro di ricerca e innovazione dell’Unione europea che riguardano i sistemi IT su larga scala nello spazio di libertà, sicurezza e giustizia. A tal fine, qualora la Commissione le abbia delegato i pertinenti poteri l’Agenzia svolge i seguenti compiti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gestione di alcune fasi di esecuzione del programma e di alcune fasi della vita di progetti specifici sulla base dei pertinenti programmi di lavoro adottati dalla Commissione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adozione degli atti di esecuzione del bilancio e delle entrate e delle spese, ed esecuzione di tutte le operazioni necessarie alla gestione del programma; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">prestazione di sostegno nell’attuazione dei programmi.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’Agenzia riferisce periodicamente e almeno una volta l’anno al Parlamento europeo, al Consiglio, alla Commissione e, per quanto riguarda il trattamento dei dati personali, al Garante europeo della protezione dei dati circa gli sviluppi di cui al presente articolo, fatti salvi gli obblighi di relazione concernenti l’attuazione delle parti del programma quadro di ricerca e innovazione dell’Unione europea di cui al paragrafo 2.</div>\n</div>"]]}, "15": {"label": "Articolo 15", "heading": "Progetti pilota, prototipi e attività di collaudo", "anchor": "art_15", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Su richiesta esplicita e circostanziata della Commissione, che ne ha informato il Parlamento europeo e il Consiglio con almeno tre mesi di anticipo, previa decisione positiva del consiglio di amministrazione, può essere affidata all’Agenzia, in conformità dell’articolo 19, paragrafo 1, lettera u), del presente regolamento, e tramite un accordo di delega, la realizzazione di progetti pilota di cui all’articolo 58, paragrafo 2, lettera a), del regolamento (UE, Euratom) 2018/1046 per lo sviluppo o la gestione operativa di sistemi IT su larga scala a norma degli articoli da 67 a 89 TFUE, in conformità dell’articolo 62, paragrafo 1, lettera c), del regolamento (UE, Euratom) 2018/1046.</p>\n<p class=\"norm inline-element\">L’Agenzia riferisce regolarmente al Parlamento europeo, al Consiglio e, per quanto riguarda il trattamento di dati personali, al Garante europeo della protezione dei dati circa l’evoluzione dei progetti pilota realizzati dall’Agenzia ai sensi del primo comma.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli stanziamenti per i progetti pilota di cui all’articolo 58, paragrafo 2, lettera a), del regolamento (UE, Euratom) 2018/1046 che sono stati richiesti dalla Commissione ai sensi del paragrafo 1 sono iscritti in bilancio per non più di due esercizi consecutivi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Su richiesta della Commissione o del Consiglio, dopo aver informato il Parlamento europeo e previa decisione positiva del consiglio di amministrazione possono essere affidati all’Agenzia, tramite un accordo di delega, compiti di esecuzione del bilancio per i prototipi finanziati nell’ambito dello strumento di sostegno finanziario per le frontiere esterne e i visti istituito dal regolamento (UE) n. 515/2014, in conformità dell’articolo 62, paragrafo 1, lettera c), del regolamento (UE, Euratom) 2018/1046.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">A seguito di una decisione positiva del consiglio di amministrazione, l’Agenzia può programmare e condurre attività di collaudo sugli aspetti contemplati dal presente regolamento e da uno degli atti giuridici dell’Unione che disciplinano lo sviluppo, l’istituzione, l’esercizio e l’uso dei sistemi.</div>\n</div>"]]}, "16": {"label": "Articolo 16", "heading": "Sostegno agli Stati membri e alla Commissione", "anchor": "art_16", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ogni Stato membro può chiedere all’Agenzia di prestargli consulenza per quanto riguarda il collegamento tra il suo sistema nazionale e i sistemi centrali dei sistemi IT su larga scala gestiti dall’Agenzia.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ogni Stato membro può presentare una richiesta di sostegno ad hoc alla Commissione, che, dopo aver stabilito che tale sostegno è necessario in virtù di esigenze eccezionali nel settore della sicurezza o della migrazione, la trasmette senza ritardo all’Agenzia. L’Agenzia comunica tali richieste al consiglio di amministrazione. Qualora la valutazione della Commissione sia negativa, lo Stato membro ne è informato.</p>\n<p class=\"norm inline-element\">La Commissione verifica se l’Agenzia ha risposto tempestivamente alla richiesta dello Stato membro. La relazione annuale di attività dell’Agenzia riporta informazioni dettagliate sulle azioni che l’Agenzia ha intrapreso per fornire sostegno ad hoc agli Stati membri e sui relativi costi.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">All’Agenzia può essere altresì chiesto di prestare consulenza o sostegno alla Commissione su questioni di carattere tecnico relative a sistemi esistenti o nuovi, anche tramite studi o collaudi. L’Agenzia informa il consiglio di amministrazione di tali richieste.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Un gruppo composto da almeno cinque Stati membri può assegnare all’Agenzia il compito di sviluppare, gestire o ospitare una componente IT comune che li assista nell’attuazione degli aspetti tecnici degli obblighi derivanti dal diritto dell’Unione sui sistemi decentrati nello spazio di libertà, sicurezza e giustizia. Tali soluzioni IT comuni lasciano impregiudicati gli obblighi che il diritto applicabile dell’Unione impone agli Stati membri richiedenti, in particolare per quanto riguarda l’architettura di tali sistemi.</p>\n<p class=\"norm inline-element\">In particolare, gli Stati membri richiedenti possono incaricare l’Agenzia di istituire una componente o un router comune per le informazioni anticipate sui passeggeri e per i dati del codice di prenotazione dei passeggeri quale strumento di assistenza tecnica per agevolare la connettività con i vettori aerei, al fine di assistere gli Stati membri nell’attuazione della direttiva 2004/82/CE del Consiglio (\n<span class=\"superscript\">10</span>\n) e della direttiva (UE) 2016/681 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">11</span>\n). In tal caso l’Agenzia raccoglie a livello centrale i dati dei vettori aerei e li trasmette agli Stati membri attraverso la componente o il router comune. Gli Stati membri richiedenti adottano le misure necessarie a garantire che i vettori aerei trasferiscano i dati tramite l’Agenzia.</p>\n<p class=\"norm inline-element\">L’Agenzia è incaricata di sviluppare, gestire o ospitare una componente IT comune unicamente previa approvazione della Commissione e in caso di decisione favorevole da parte del consiglio di amministrazione.</p>\n<p class=\"norm inline-element\">Gli Stati membri richiedenti affidano all’Agenzia i compiti di cui al primo e al secondo comma tramite un accordo di delega che definisce le condizioni per la delega dei compiti nonché il calcolo di tutti i costi pertinenti e il metodo di fatturazione. Tutti i costi pertinenti sono coperti dagli Stati membri partecipanti. L’accordo di delega è conforme agli atti giuridici dell’Unione che disciplinano i sistemi in questione. L’Agenzia informa il Parlamento europeo e il Consiglio dell’accordo di delega approvato e delle eventuali modifiche apportate allo stesso.</p>\n<p class=\"norm inline-element\">Altri Stati membri possono chiedere di partecipare a una soluzione IT comune se tale possibilità è prevista dall’accordo di delega, precisando in particolare le conseguenze finanziarie di tale partecipazione. L’accordo di delega è modificato di conseguenza, previe approvazione preliminare della Commissione e decisione favorevole del consiglio di amministrazione.</p>\n</div>\n</div>"]]}, "17": {"label": "Articolo 17", "heading": "Status giuridico e ubicazione", "anchor": "art_17", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’Agenzia è un organismo dell’Unione ed è dotata di personalità giuridica.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’Agenzia gode della più ampia capacità giuridica riconosciuta alle persone giuridiche dal diritto nazionale in ciascuno Stato membro. In particolare, può acquistare o alienare beni mobili e immobili e può stare in giudizio.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M7\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’Agenzia ha sede a Tallinn (Estonia).</div>\n</div>"], [null, "<p class=\"norm\">I compiti relativi allo sviluppo e alla gestione operativa di cui all’articolo 1, paragrafi 4 e 5, agli articoli da 3 a 9 e agli articoli 11 e 13 <span class=\"italics\">bis</span> sono svolti nel sito tecnico di Strasburgo (Francia).</p>"], [null, "<p class=\"norm\">Un sito di riserva in grado di assicurare il funzionamento di un sistema IT su larga scala in caso di guasto di tale sistema è installato a Sankt Johann im Pongau (Austria).</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Entrambi i siti tecnici possono essere utilizzati per far funzionare simultaneamente i sistemi, purché in caso di guasto di uno o più sistemi il sito di riserva resti in grado di garantirne il funzionamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">In ragione della natura specifica dei sistemi, qualora dovesse rendersi necessario per l’Agenzia istituire un secondo sito tecnico distinto a Strasburgo o a Sankt Johann im Pongau, o in entrambi i luoghi, secondo la necessità, al fine di ospitare i sistemi, tale necessità è motivata sulla base di una valutazione d’impatto e di un’analisi costi-benefici indipendenti. Il consiglio di amministrazione consulta la Commissione e tiene conto del suo punto di vista prima di notificare all’autorità di bilancio l’intenzione di realizzare un progetto di natura immobiliare conformemente all’articolo 45, paragrafo 9.</div>\n</div>"]]}, "18": {"label": "Articolo 18", "heading": "Struttura", "anchor": "art_18", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La struttura amministrativa e gestionale dell’Agenzia è composta da:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un consiglio di amministrazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un direttore esecutivo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gruppi consultivi.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La struttura dell’Agenzia comprende:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un responsabile della protezione dei dati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un responsabile della sicurezza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un contabile.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "19": {"label": "Articolo 19", "heading": "Funzioni del consiglio di amministrazione", "anchor": "art_19", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il consiglio di amministrazione:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fornisce orientamenti generali per le attività dell’Agenzia;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adotta, a maggioranza dei due terzi dei membri con diritto di voto, il bilancio annuale dell’Agenzia ed esercita altre funzioni in relazione al bilancio dell’Agenzia a norma del capo V;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nomina il direttore esecutivo e il vicedirettore esecutivo e, se del caso, ne proroga i rispettivi mandati o li rimuove dall’incarico a norma, rispettivamente, degli articoli 25 e 26;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">esercita l’autorità disciplinare nei confronti del direttore esecutivo e ne controlla l’operato, compresa l’esecuzione delle decisioni del consiglio di amministrazione, ed esercita l’autorità disciplinare nei confronti del vicedirettore esecutivo, d’accordo con il direttore esecutivo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">prende tutte le decisioni sull’istituzione della struttura organizzativa dell’Agenzia e, se necessario, sulla relativa modifica, in considerazione delle necessità per l’attività dell’Agenzia e secondo una sana gestione di bilancio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adotta la politica dell’Agenzia in materia di personale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">stabilisce il regolamento interno dell’Agenzia;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adotta una strategia antifrode, proporzionata al rischio di frode, tenendo conto dei costi e dei benefici delle misure da attuare;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adotta norme di prevenzione e gestione dei conflitti di interesse in relazione ai suoi membri e le pubblica sul sito web dell’Agenzia;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adotta norme e procedure interne dettagliate per la protezione degli informatori, compresi canali adeguati di comunicazione per la segnalazione di irregolarità;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">autorizza la conclusione di accordi operativi conformemente agli articoli 41 e 43;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>l) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">approva, su proposta del direttore esecutivo, l’accordo sulla sede dell’Agenzia e gli accordi sui siti tecnici e di riserva, stabiliti in conformità dell’articolo 17, paragrafo 3, che il direttore esecutivo e gli Stati membri ospitanti devono firmare;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>m) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">esercita, ai sensi del paragrafo 2, nei confronti del personale dell’Agenzia, i poteri conferiti dallo statuto dei funzionari all’autorità che ha il potere di nomina e dal regime applicabile agli altri agenti all’autorità abilitata a concludere i contratti di assunzione («poteri dell’autorità che ha il potere di nomina»);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>n) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adotta, in accordo con la Commissione, le disposizioni di attuazione necessarie per dare effetto allo statuto dei funzionari conformemente all’articolo 110 dello statuto dei funzionari;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>o) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adotta le necessarie disposizioni relative al distacco di esperti nazionali presso l’Agenzia;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>p) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adotta un progetto di stato di previsione delle entrate e delle spese dell’Agenzia, comprensivo di un progetto di tabella dell’organico, e lo presenta alla Commissione entro il 31 gennaio di ogni anno;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>q) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adotta il progetto di documento unico di programmazione, che contiene la programmazione pluriennale dell’Agenzia, il suo programma di lavoro per l’anno successivo e un progetto provvisorio di stato di previsione delle entrate e delle spese dell’Agenzia comprensivo di un progetto di tabella dell’organico, e lo presenta, unitamente a qualsiasi versione aggiornata di tale documento, al Parlamento europeo, al Consiglio e alla Commissione entro il 31 gennaio di ogni anno;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>r) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adotta, entro il 30 novembre di ogni anno, a maggioranza dei due terzi dei membri aventi diritto di voto, conformemente alla procedura annuale di bilancio, il documento unico di programmazione tenendo conto del parere della Commissione e provvede a che il testo definitivo di tale documento unico di programmazione sia trasmesso al Parlamento europeo, al Consiglio e alla Commissione e pubblicato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>s) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adotta, entro la fine di agosto di ogni anno, una relazione intermedia sui progressi compiuti nell’attuazione delle attività programmate per l’anno in corso e la presenta al Parlamento europeo, al Consiglio e alla Commissione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>t) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">valuta e adotta la relazione annuale di attività consolidata delle attività dell’Agenzia per l’anno precedente, in cui confronta, in particolare, i risultati ottenuti con gli obiettivi del programma di lavoro annuale e, entro il 1<span class=\"superscript\">o</span> luglio di ogni anno, trasmette sia la relazione che la relativa valutazione al Parlamento europeo, al Consiglio, alla Commissione e alla Corte dei conti e assicura che la relazione annuale di attività sia pubblicata;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>u) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">svolge le funzioni attribuitegli in relazione al bilancio dell’Agenzia, compresa la realizzazione dei progetti pilota e dei prototipi di cui all’articolo 15;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>v) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adotta la regolamentazione finanziaria applicabile all’Agenzia in conformità dell’articolo 49;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>w) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nomina un contabile, che può essere il contabile della Commissione, che è soggetto allo statuto dei funzionari e opera in piena indipendenza nell’esercizio delle sue funzioni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>x) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">assicura un seguito adeguato alle osservazioni e alle raccomandazioni risultanti dalle varie relazioni di audit e valutazioni interne e esterne, e dalle indagini dell’Ufficio europeo per la lotta antifrode (OLAF) e della procura europea (EPPO);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>y) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adotta i piani di comunicazione e divulgazione di cui all’articolo 34, paragrafo 4, e li aggiorna periodicamente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>z) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adotta le misure di sicurezza necessarie, compresi un piano di sicurezza e un piano di continuità operativa e di ripristino in caso di disastro, tenendo conto delle eventuali raccomandazioni degli esperti di sicurezza che fanno parte dei gruppi consultivi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>aa) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">previa approvazione della Commissione, adotta le norme di sicurezza per la protezione delle informazioni classificate e delle informazioni sensibili non classificate;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>bb) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nomina un responsabile della sicurezza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>cc) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nomina un responsabile della protezione dei dati conformemente al regolamento (UE) 2018/1725;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>dd) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adotta le modalità pratiche di attuazione del regolamento (CE) n. 1049/2001;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ee) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adotta le relazioni sullo sviluppo dell'EES conformemente all'articolo 72, paragrafo 2, del regolamento (UE) 2017/2226, le relazioni sullo sviluppo dell'ETIAS conformemente all'articolo 92, paragrafo 2, del regolamento (UE) 2018/1240 e le relazioni sullo sviluppo di ECRIS-TCN e dell'<span>\n<span class=\"boldface\">►C4</span>\n</span> implementazione di riferimento ECRIS<span class=\"boldface\"> ◄ </span> conformemente all'articolo 36, paragrafo 3, del regolamento (UE) 2019/816;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M2\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ee <span class=\"italics\">bis</span>) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adotta relazioni sulla situazione dello sviluppo delle componenti dell'interoperabilità a norma dell'articolo 78, paragrafo 2, del regolamento (UE) 2019/817 e dell'articolo 74, paragrafo 2, del regolamento (UE) 2019/818;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M6\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ee ter) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adotta relazioni sulla situazione dello sviluppo del router Prüm II in conformità dell’articolo 80, paragrafo 2 del regolamento (UE) 2024/982;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M7\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ee <span class=\"italics\">ter</span>) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adotta relazioni sulla situazione dello sviluppo del router in conformità dell’articolo 45, paragrafo 2 del regolamento (UE) 2025/12;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M6\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ff) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adotta relazioni sul funzionamento tecnico di quanto segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il SIS in conformità dell’articolo 60, paragrafo 7, del regolamento (UE) 2018/1861 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">12</span>\n) e dell’articolo 74, paragrafo 8, del regolamento (UE) 2018/1862 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">13</span>\n);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il VIS in conformità dell’articolo 50, paragrafo 3, del regolamento (CE) n. 767/2008 e dell’articolo 17, paragrafo 3, della decisione 2008/633/GAI;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’EES in conformità dell’articolo 72, paragrafo 4, del regolamento (UE) 2017/2226;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’ETIAS in conformità dell’articolo 92, paragrafo 4, del regolamento (UE) 2018/1240;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>v) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’ECRIS-TCN e dell’implementazione di riferimento ECRIS in conformità dell’articolo 36, paragrafo 8, del regolamento (UE) 2019/816;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M7\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>vi) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">delle componenti dell’interoperabilità in conformità dell’articolo 78, paragrafo 3, del regolamento (UE) 2019/817 e dell’articolo 74, paragrafo 3, del regolamento (UE) 2019/818, e del router in conformità dell’articolo 80, paragrafo 5, del regolamento (UE) 2024/982 e dell’articolo 45, paragrafo 5, del regolamento (UE) 2025/12;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M6\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>vii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il sistema e-CODEX in conformità dell’articolo 16, paragrafo 1, del regolamento (UE) 2022/850;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>viii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la piattaforma di collaborazione per le SIC in conformità dell’articolo 26, paragrafo 6, del regolamento (UE) 2023/969;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ix) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il router Prüm II in conformità dell’articolo 80, paragrafo 5, del regolamento (UE) 2024/982;</p>\n</div>\n</div>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>gg) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adotta la relazione annuale sulle attività del sistema centrale di Eurodac conformemente all’articolo 40, paragrafo 1, del regolamento (UE) n. 603/2013;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M7\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>hh) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adotta osservazioni formali sulle relazioni del Garante europeo della protezione dei dati relative ai suoi controlli in conformità dell’articolo 56, paragrafo 2, del regolamento (UE) 2018/1861, dell’articolo 42, paragrafo 2, del regolamento (CE) n. 767/2008, dell’articolo 31, paragrafo 2, del regolamento (UE) n. 603/2013, dell’articolo 56, paragrafo 2, del regolamento (UE) 2017/2226, dell’articolo 67 del regolamento (UE) 2018/1240, dell’articolo 29, paragrafo 2, del regolamento (UE) 2019/816, dell’articolo 52 dei regolamenti (UE) 2019/817 e (UE) 2019/818, dell’articolo 58, paragrafo 1, del regolamento (UE) 2024/982 e dell’articolo 22, paragrafo 3, del regolamento (UE) 2025/12. e assicura adeguato seguito a tali controlli;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">pubblica le statistiche relative al SIS II in conformità, rispettivamente, dell’articolo 50, paragrafo 3, del regolamento (CE) n. 1987/2006 e dell’articolo 66, paragrafo 3, della decisione 2007/533/GAI;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>jj) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">elabora e pubblica statistiche sulle attività del sistema centrale dell’Eurodac in conformità dell’articolo 8, paragrafo 2, del regolamento (UE) n. 603/2013;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>kk) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">pubblica le statistiche relative all’EES in conformità dell’articolo 63 del regolamento (UE) 2017/2226;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ll) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">pubblica le statistiche relative all’ETIAS in conformità dell’articolo 84 del regolamento (UE) 2018/1240;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ll <span class=\"italics\">bis</span>) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">trasmette alla Commissione statistiche su ECRIS-TCN e sull'<span>\n<span class=\"boldface\">►C4</span>\n</span> implementazione di riferimento ECRIS<span class=\"boldface\"> ◄ </span> conformemente all'articolo 32, paragrafo 4, secondo comma, del regolamento (UE) 2019/816;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M4\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>mm) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">provvede alla pubblicazione annuale:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dell’elenco delle autorità competenti autorizzate a consultare direttamente i dati inseriti nel SIS in conformità dell’articolo 41, paragrafo 8, del regolamento (UE) 2018/1861 e dell’articolo 56, paragrafo 7, del regolamento (UE) 2018/1862, nonché dell’elenco degli uffici dei sistemi nazionali del SIS (N.SIS) e degli uffici SIRENE di cui, rispettivamente, all’articolo 7, paragrafo 3, del regolamento (UE) 2018/1861 e all’articolo 7, paragrafo 3, del regolamento (UE) 2018/1862;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dell’elenco delle autorità competenti di cui all’articolo 65, paragrafo 2, del regolamento (UE) 2017/2226;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dell’elenco delle autorità competenti di cui all’articolo 87, paragrafo 2, del regolamento (UE) 2018/1240;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dell’elenco delle autorità centrali di cui all’articolo 34, paragrafo 2, del regolamento (UE) 2019/816;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>v) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dell’elenco delle autorità di cui all’articolo 71, paragrafo 1, del regolamento (UE) 2019/817 e all’articolo 67, paragrafo 1, del regolamento (UE) 2019/818;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>vi) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dell’elenco dei punti di accesso e-CODEX autorizzati a norma dell’articolo 7, paragrafo 1, lettera h), del regolamento (UE) 2022/850;</p>\n</div>\n</div>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>nn) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">provvede alla pubblicazione annuale dell’elenco delle unità conformemente all’articolo 27, paragrafo 2, del regolamento (UE) n. 603/2013;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>oo) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">assicura che tutte le decisioni e azioni dell’Agenzia che interessano i sistemi IT su larga scala nello spazio di libertà, sicurezza e giustizia rispettino il principio di indipendenza della magistratura;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>pp) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">svolge ogni altro compito conferitogli conformemente al presente regolamento.</p>\n</div>\n</div>\n<p class=\"norm inline-element\">Fatte salve le disposizioni relative alla pubblicazione degli elenchi delle autorità competenti previste dagli atti giuridici dell’Unione di cui al primo comma, lettera mm), e ove tali atti giuridici non prevedano l’obbligo di pubblicare e aggiornare costantemente tali elenchi sul sito web dell’Agenzia, il consiglio di amministrazione ne garantisce la pubblicazione e gli aggiornamenti continui.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il consiglio di amministrazione adotta, in conformità dell’articolo 110 dello statuto dei funzionari, una decisione basata sull’articolo 2, paragrafo 1, dello statuto dei funzionari e sull’articolo 6 del regime applicabile agli altri agenti con cui delega al direttore esecutivo i poteri di autorità che ha il potere di nomina e stabilisce le condizioni di sospensione della delega di tali poteri. Il direttore esecutivo è autorizzato a subdelegare tali poteri.</p>\n<p class=\"norm inline-element\">Qualora circostanze eccezionali lo richiedano, il consiglio di amministrazione può, mediante decisione, sospendere temporaneamente la delega dei poteri di autorità che ha il potere di nomina delegati al direttore esecutivo e quelli subdelegati da quest’ultimo, ed esercitarli esso stesso o delegarli a uno dei suoi membri o a un membro del personale diverso dal direttore esecutivo.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il consiglio di amministrazione può consigliare il direttore esecutivo su qualsiasi questione strettamente legata allo sviluppo o alla gestione operativa dei sistemi IT su larga scala e alle attività collegate alla ricerca, ai progetti pilota, ai prototipi e ai collaudi.</div>\n</div>"]]}, "20": {"label": "Articolo 20", "heading": "Composizione del consiglio di amministrazione", "anchor": "art_20", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il consiglio di amministrazione è composto di un rappresentante di ciascuno Stato membro e di due rappresentanti della Commissione. Ogni rappresentante ha diritto di voto a norma dell’articolo 23.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ciascun membro del consiglio di amministrazione ha un supplente. Il supplente assume la rappresentanza del membro in sua assenza o nel caso in cui il membro sia eletto presidente o vicepresidente del consiglio di amministrazione e presieda la riunione del consiglio di amministrazione. I membri del consiglio di amministrazione e i loro supplenti sono nominati in base all’alto livello della loro esperienza e competenza in materia di sistemi IT su larga scala nello spazio di libertà, sicurezza e giustizia e alle loro conoscenze in materia di protezione di dati, tenuto conto delle loro competenze di tipo gestionale, amministrativo e di bilancio. Tutte le parti rappresentate nel consiglio di amministrazione si sforzano di limitare l’avvicendamento dei rispettivi rappresentanti per assicurare la continuità dei lavori del consiglio di amministrazione. Tutte le parti si adoperano per conseguire una rappresentanza di genere equilibrata nel consiglio di amministrazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La durata del mandato dei membri e dei loro supplenti è di quattro anni ed è rinnovabile. Alla scadenza del mandato o in caso di dimissioni i membri restano in carica fino al rinnovo del mandato o fino alla loro sostituzione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">I paesi associati all’attuazione, all’applicazione e allo sviluppo dell’acquis di Schengen e alle misure relative al regolamento Dublino e all’Eurodac partecipano alle attività dell’Agenzia. Ciascuno di essi nomina un rappresentante e un supplente nel consiglio di amministrazione.</div>\n</div>"]]}, "21": {"label": "Articolo 21", "heading": "Presidente del consiglio di amministrazione", "anchor": "art_21", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il consiglio di amministrazione elegge un presidente e un vicepresidente fra i propri membri nominati dagli Stati membri che, in base al diritto dell’Unione, sono pienamente vincolati da tutti gli atti giuridici dell’Unione che disciplinano lo sviluppo, l’istituzione, l’esercizio e l’uso di tutti i sistemi IT su larga scala gestiti dall’Agenzia. Il presidente e il vicepresidente sono eletti a maggioranza di due terzi dei membri del consiglio di amministrazione con diritto di voto.</p>\n<p class=\"norm inline-element\">Il vicepresidente sostituisce d’ufficio il presidente in caso di suo impedimento.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il mandato del presidente e del vicepresidente è di quattro anni. Il mandato è rinnovabile una volta. Qualora l’appartenenza del presidente e del vicepresidente al consiglio di amministrazione termini in un qualsiasi momento in corso di mandato, questo scade automaticamente alla stessa data.</div>\n</div>"]]}, "22": {"label": "Articolo 22", "heading": "Riunioni del consiglio di amministrazione", "anchor": "art_22", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le riunioni del consiglio di amministrazione sono indette dal presidente.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il direttore esecutivo partecipa alle deliberazioni del consiglio di amministrazione, senza diritto di voto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il consiglio di amministrazione tiene almeno due riunioni ordinarie all’anno. Si riunisce inoltre su iniziativa del presidente, su richiesta della Commissione, su richiesta del direttore esecutivo o su richiesta di almeno un terzo dei membri del consiglio di amministrazione con diritto di voto.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Europol e Eurojust possono assistere alle riunioni del consiglio di amministrazione in qualità di osservatori quando sono all'ordine del giorno questioni concernenti il SIS II, in relazione all'applicazione della decisione 2007/533/GAI.</div>\n</div>"], [null, "<p class=\"norm\">L'Agenzia europea della guardia di frontiera e costiera può assistere alle riunioni del consiglio di amministrazione in qualità di osservatore quando sono all'ordine del giorno questioni concernenti il SIS, in relazione all'applicazione del regolamento (UE) 2016/1624.</p>"], [null, "<p class=\"norm\">Europol può assistere alle riunioni del consiglio di amministrazione in qualità di osservatore quando sono all'ordine del giorno questioni concernenti il VIS, in relazione all'applicazione della decisione 2008/633/GAI, o questioni concernenti l'Eurodac, in relazione all'applicazione del regolamento (UE) n. 603/2013.</p>"], [null, "<p class=\"norm\">Europol può assistere alle riunioni del consiglio di amministrazione in qualità di osservatore quando sono all'ordine del giorno questioni concernenti l'EES, in relazione all'applicazione del regolamento (UE) 2017/2226, o questioni concernenti l'ETIAS, in relazione al regolamento (UE) 2018/1240.</p>"], [null, "<p class=\"norm\">L'Agenzia europea della guardia di frontiera e costiera può assistere alle riunioni del consiglio di amministrazione in qualità di osservatore anche quando è all'ordine del giorno una questione concernente l'ETIAS in relazione all'applicazione del regolamento (UE) 2018/1240.</p>"], [null, "<p class=\"norm\">Europol, Eurojust e la Procura europea possono assistere alle riunioni del consiglio di amministrazione in qualità di osservatori quando è all'ordine del giorno una questione concernente il regolamento (UE) 2019/816.</p>"], [null, "<p class=\"norm\">Europol, Eurojust e l'Agenzia europea della guardia di frontiera e costiera possono assistere alle riunioni del consiglio di amministrazione in qualità di osservatori quando è all'ordine del giorno una questione concernente il regolamento (UE) 2019/817 e (UE) 2019/818.</p>"], [null, "<p class=\"norm\">Il consiglio di amministrazione può invitare qualsiasi altra persona, il cui parere possa essere rilevante, a presenziare alle riunioni in veste di osservatore.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">I membri del consiglio di amministrazione e i loro supplenti possono farsi assistere da consulenti o esperti, in particolare membri dei gruppi consultivi, fatte salve le disposizioni del regolamento interno del consiglio di amministrazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">L’Agenzia provvede alle funzioni di segreteria del consiglio di amministrazione.</div>\n</div>"]]}, "23": {"label": "Articolo 23", "heading": "Modalità di voto del consiglio di amministrazione", "anchor": "art_23", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Fatti salvi il paragrafo 5 del presente articolo, l’articolo 19, paragrafo 1, lettere b) e r), l’articolo 21, paragrafo 1, e l’articolo 25, paragrafo 8, le decisioni del consiglio di amministrazione sono adottate a maggioranza dei membri aventi diritto di voto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Fatti salvi i paragrafi 3 e 4, ogni membro del consiglio di amministrazione dispone di un voto. In assenza di un membro con diritto di voto, il supplente è abilitato a esercitare il suo diritto di voto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ogni membro nominato da uno Stato membro che, in base al diritto dell’Unione, è vincolato da qualsiasi atto giuridico dell’Unione che disciplini lo sviluppo, l’istituzione, l’esercizio e l’uso di un sistema IT su larga scala gestito dall’Agenzia può votare sulle questioni riguardanti quel sistema.</p>\n<p class=\"norm inline-element\">La Danimarca può votare sulle questioni riguardanti un sistema IT su larga scala qualora decida, ai sensi dell’articolo 4 del protocollo n. 22, di recepire nel proprio diritto interno l’atto giuridico dell’Unione che disciplina lo sviluppo, l’istituzione, l’esercizio e l’uso di tale particolare sistema IT su larga scala.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L’articolo 42 si applica al diritto di voto dei rappresentanti dei paesi che hanno concluso con l’Unione accordi riguardanti la loro associazione all’attuazione, all’applicazione e allo sviluppo dell’acquis di Schengen e alle misure relative al regolamento Dublino e a Eurodac.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">In caso di disaccordo tra i membri sulla questione se una votazione riguardi o meno uno specifico sistema IT su larga scala, qualsiasi decisione che stabilisca che la votazione non riguarda tale specifico sistema IT su larga scala è adottata a maggioranza dei due terzi dei membri del consiglio di amministrazione aventi diritto di voto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Il presidente, o il vicepresidente quando sostituisce il presidente, non vota. Il diritto di voto del presidente, o del vicepresidente quando sostituisce il presidente, è esercitato dal suo supplente.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Il direttore esecutivo non vota.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Il regolamento interno del consiglio di amministrazione stabilisce in modo più dettagliato le regole di voto, in particolare le condizioni alle quali un membro può agire a nome di un altro e, se del caso, i requisiti relativi al quorum.</div>\n</div>"]]}, "24": {"label": "Articolo 24", "heading": "Compiti del direttore esecutivo", "anchor": "art_24", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il direttore esecutivo assicura la gestione dell’Agenzia. Il direttore esecutivo assiste e risponde al consiglio di amministrazione. Su richiesta, il direttore esecutivo riferisce al Parlamento europeo sull’esercizio delle sue funzioni. Il Consiglio può invitare il direttore esecutivo a riferire sull’esercizio delle sue funzioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il direttore esecutivo è il rappresentante legale dell’Agenzia.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il direttore esecutivo è responsabile dell’esecuzione dei compiti conferiti all’Agenzia dal presente regolamento. In particolare, il direttore esecutivo è responsabile di quanto segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">amministrazione corrente dell’Agenzia;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">funzionamento dell’Agenzia conformemente al presente regolamento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">preparare e applicare le procedure, le decisioni e le strategie, i programmi e le attività adottate dal consiglio di amministrazione, nei limiti previsti dal presente regolamento, dalle relative modalità di attuazione e dal diritto dell’Unione applicabile;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">preparare il documento unico di programmazione e presentarlo al consiglio di amministrazione previa consultazione della Commissione e dei gruppi consultivi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">attuare il documento unico di programmazione e riferire in merito al consiglio di amministrazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">preparare una relazione intermedia sui progressi compiuti nell’attuazione delle attività programmate per l’anno in corso e, previa consultazione dei gruppi consultivi, presentarla al consiglio di amministrazione per adozione entro la fine di agosto di ogni anno;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">redigere la relazione annuale di attività consolidata dell’Agenzia e, previa consultazione dei gruppi consultivi, presentarla al consiglio di amministrazione per valutazione e adozione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">elaborare un piano d’azione volto a dare seguito alle conclusioni delle relazioni di audit e valutazioni interne o esterne e alle indagini dell’OLAF e dell’EPPO, e informare due volte l’anno la Commissione sui progressi compiuti e periodicamente il consiglio di amministrazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tutelare gli interessi finanziari dell’Unione mediante l’applicazione di misure di prevenzione contro le frodi, la corruzione e qualsiasi altra attività illecita, fatti salvi i poteri investigativi dell’EPPO e dell’OLAF, attraverso controlli effettivi e, nel caso in cui siano riscontrate irregolarità, il recupero delle somme indebitamente corrisposte e, se del caso, mediante l’applicazione di sanzioni amministrative effettive, proporzionate e dissuasive, anche di carattere pecuniario;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">preparare una strategia antifrode dell’Agenzia e presentarla al consiglio di amministrazione per approvazione, come pure monitorarne la corretta e tempestiva attuazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">redigere un progetto di regolamentazione finanziaria applicabile all’Agenzia e presentarlo al consiglio di amministrazione per adozione, previa consultazione della Commissione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>l) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">preparare il progetto di bilancio per l’esercizio successivo, elaborato in base al sistema della formazione del bilancio per attività;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>m) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">redigere il progetto di stato di previsione delle spese e delle entrate dell’Agenzia;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>n) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">attuare il bilancio dell’Agenzia;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>o) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">definire e attuare un sistema efficace di valutazione e controllo periodici:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dei sistemi IT su larga scala, comprese le statistiche; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dell’Agenzia, ivi inclusa la realizzazione efficiente ed efficace dei suoi obiettivi;</p>\n</div>\n</div>\n</div>\n</div>\n<p class=\"modref\">\n▼M1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>p) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fatto salvo l'articolo 17 dello statuto dei funzionari, stabilire le clausole di riservatezza per conformarsi all'articolo 17 del regolamento (CE) n. 1987/2006, all'articolo 17 della decisione 2007/533/GAI, all'articolo 26, paragrafo 9, del regolamento (CE) n. 767/2008, all'articolo 4, paragrafo 4, del regolamento (UE) n. 603/2013, all'articolo 37, paragrafo 4, del regolamento (UE) 2017/2226, all'articolo 74, paragrafo 2, del regolamento (UE) 2018/1240, all'articolo 11, paragrafo 16, del regolamento (UE) 2019/816 e all'articolo 55, paragrafo 2, dei regolamenti (UE) 2019/817 e (UE) 2019/818;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>q) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">negoziare e, previa approvazione del consiglio di amministrazione, firmare con gli Stati membri ospitanti l’accordo sulla sede dell’Agenzia e gli accordi relativi ai siti tecnici e di riserva;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>r) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">preparare le modalità pratiche per l’attuazione del regolamento (CE) n. 1049/2001 e presentarle al consiglio di amministrazione per adozione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>s) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">elaborare le misure di sicurezza necessarie, compresi un piano di sicurezza e un piano di continuità operativa e di ripristino in caso di disastro e, previa consultazione del pertinente gruppo consultivo, presentarli al consiglio di amministrazione per adozione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>t) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sulla base dei risultati del controllo e della valutazione, predisporre le relazioni sul funzionamento tecnico di ogni sistema IT su larga scala di cui all’articolo 19, paragrafo 1, lettera ff), e la relazione annuale sulle attività del sistema centrale dell’Eurodac di cui all’articolo 19, paragrafo 1, lettera gg), e, previa consultazione del pertinente gruppo consultivo, presentarle al consiglio di amministrazione per adozione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>u) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">preparare le relazioni sullo sviluppo dell’EES di cui all’articolo 72, paragrafo 2, del regolamento (UE) 2017/2226 e sullo sviluppo dell’ETIAS di cui all’articolo 92, paragrafo 2, del regolamento (UE) 2018/1240 e presentarle al consiglio di amministrazione per adozione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>v) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">preparare, a fini di pubblicazione, l’elenco annuale delle autorità competenti autorizzate a consultare direttamente i dati inseriti nel SIS II, compreso l’elenco degli uffici N.SIS II e degli uffici SIRENE, e l’elenco delle autorità competenti autorizzate a consultare direttamente i dati inseriti nell’EES e nell’ETIAS di cui all’articolo 19, paragrafo 1, lettera mm), e gli elenchi delle unità di cui all’articolo 19, paragrafo 1, lettera nn), e presentarli al consiglio di amministrazione per adozione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il direttore esecutivo svolge ogni altro compito conformemente al presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il direttore esecutivo decide se sia necessario collocare uno o più membri del personale in uno o più Stati membri per svolgere i compiti dell’Agenzia in maniera efficiente ed efficace ed istituire un ufficio locale a tal fine. Prima di adottare tale decisione, il direttore esecutivo deve ottenere il consenso della Commissione, del consiglio di amministrazione e dello Stato membro o degli Stati membri interessati. La decisione del direttore esecutivo precisa l’ambito delle attività che devono essere espletate presso l’ufficio locale al fine di evitare costi inutili e duplicazioni di funzioni amministrative dell’Agenzia. Le attività svolte nei siti tecnici non sono eseguite in un ufficio locale.</div>\n</div>"]]}, "25": {"label": "Articolo 25", "heading": "Nomina del direttore esecutivo", "anchor": "art_25", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il consiglio di amministrazione nomina il direttore esecutivo sulla base di un elenco di almeno tre candidati proposto dalla Commissione, secondo una procedura di selezione aperta e trasparente. La procedura di selezione prevede la pubblicazione di un invito a manifestare interesse nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span> e in altri strumenti d’informazione adeguati. Il consiglio di amministrazione nomina il direttore esecutivo sulla base dei meriti, dell’esperienza comprovata in materia di sistemi IT su larga scala, delle capacità amministrative, finanziarie e gestionali e delle conoscenze in materia di protezione di dati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Prima della nomina, i candidati proposti dalla Commissione sono invitati a rendere una dichiarazione dinanzi alla commissione o alle commissioni competenti del Parlamento europeo e a rispondere alle domande dei membri delle commissioni. Dopo aver sentito la dichiarazione e le risposte, il Parlamento europeo adotta un parere e può esprimere una preferenza per un candidato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il consiglio di amministrazione nomina il direttore esecutivo tenendo conto di tale opinione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Se il consiglio di amministrazione decide di nominare un candidato diverso da quello per il quale il Parlamento europeo aveva espresso una preferenza, informa per iscritto il Parlamento europeo e il Consiglio del modo in cui è stato tenuto conto del parere del Parlamento europeo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il mandato del direttore esecutivo è di cinque anni. Entro la fine di tale periodo la Commissione effettua una valutazione che tiene conto dei risultati ottenuti dal direttore esecutivo e dei compiti e delle sfide futuri dell’Agenzia.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Agendo su proposta della Commissione, la quale tiene conto della valutazione di cui al paragrafo 5, il consiglio di amministrazione può prorogare il mandato del direttore esecutivo una sola volta, per non più di cinque anni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Il consiglio di amministrazione informa il Parlamento europeo dell’intenzione di prorogare il mandato del direttore esecutivo. Entro il mese precedente tale proroga, il direttore esecutivo è invitato a rendere una dichiarazione dinanzi alla commissione o alle commissioni competenti del Parlamento europeo e a rispondere alle domande dei membri delle commissioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Il direttore esecutivo il cui mandato sia stato prorogato non può partecipare a un’altra procedura di selezione per lo stesso posto alla fine del periodo complessivo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Il direttore esecutivo può essere rimosso dall’incarico solo su decisione del consiglio di amministrazione, che agisce su proposta della maggioranza dei membri aventi diritto di voto o della Commissione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">10.  </span>\n<div class=\"norm inline-element\">Il consiglio di amministrazione adotta le decisioni riguardanti la nomina del direttore esecutivo, la proroga del suo mandato e la sua rimozione dall’incarico a maggioranza di due terzi dei membri aventi diritto di voto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">11.  </span>\n<div class=\"norm inline-element\">Ai fini della conclusione del contratto di lavoro con il direttore esecutivo l’Agenzia è rappresentata dal presidente del consiglio di amministrazione. Il direttore esecutivo è assunto come agente temporaneo dell’Agenzia ai sensi dell’articolo 2, lettera a), del regime applicabile agli altri agenti.</div>\n</div>"]]}, "26": {"label": "Articolo 26", "heading": "Vicedirettore esecutivo", "anchor": "art_26", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il direttore esecutivo è assistito da un vicedirettore esecutivo. Il vicedirettore esecutivo fa altresì le veci del direttore esecutivo in sua assenza. Il direttore esecutivo definisce le funzioni del vicedirettore esecutivo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il vicedirettore esecutivo è nominato dal consiglio d’amministrazione su proposta del direttore esecutivo. Il vicedirettore esecutivo è nominato sulla base del merito e di adeguate competenze in materia amministrativa e gestionale, compresa una pertinente esperienza professionale. Il direttore esecutivo propone almeno tre candidati per il posto di vicedirettore esecutivo. Il consiglio d’amministrazione delibera a maggioranza dei due terzi dei membri aventi diritto di voto. Il consiglio di amministrazione ha la facoltà di revocare il vicedirettore esecutivo mediante decisione adottata a maggioranza di due terzi dei membri aventi diritto di voto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il mandato del vicedirettore esecutivo ha una durata di cinque anni. Il consiglio d’amministrazione può prorogare tale mandato una sola volta, per un periodo della durata massima di cinque anni. Il consiglio d’amministrazione adotta tale decisione a maggioranza dei due terzi dei membri aventi diritto di voto.</div>\n</div>"]]}, "27": {"label": "Articolo 27", "heading": "Gruppi consultivi", "anchor": "art_27", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">I seguenti gruppi consultivi forniscono al consiglio di amministrazione le competenze tecniche relative ai sistemi IT su larga scala, in particolare nel contesto della preparazione del programma di lavoro annuale e della relazione annuale di attività:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gruppo consultivo SIS II;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gruppo consultivo VIS;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gruppo consultivo Eurodac;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gruppo consultivo EES-ETIAS;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d <span class=\"italics\">bis</span>) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gruppo consultivo di ECRIS-TCN;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼C1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d <span class=\"italics\">ter</span>) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gruppo consultivo sull’interoperabilità;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M4\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d <span class=\"italics\">quater</span>) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gruppo consultivo e-CODEX;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M5\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d <span class=\"italics\">quinquies</span>) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gruppo consultivo della piattaforma di collaborazione per le SIC;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M7\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d sexies) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gruppo consultivo API-PNR;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ogni altro gruppo consultivo relativo a un sistema IT su larga scala, se così previsto dal pertinente atto giuridico dell’Unione che ne disciplina lo sviluppo, l’istituzione, l’esercizio e l’uso.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ogni Stato membro che, in base al diritto dell’Unione, sia vincolato da un atto giuridico dell’Unione che disciplini lo sviluppo, l’istituzione, l’esercizio e l’uso di un dato sistema IT su larga scala e la Commissione nominano un membro in seno al gruppo consultivo relativo a quel sistema IT su larga scala, con un mandato di quattro anni rinnovabile.</p>\n<p class=\"norm inline-element\">La Danimarca nomina un membro in seno al gruppo consultivo relativo a un dato sistema IT su larga scala qualora decida, ai sensi dell’articolo 4 del protocollo n. 22, di recepire nel proprio diritto interno l’atto giuridico dell’Unione che disciplina lo sviluppo, l’istituzione, l’esercizio e l’uso di quel sistema IT su larga scala.</p>\n<p class=\"norm inline-element\">Ciascun paese associato all’attuazione, all’applicazione e allo sviluppo dell’acquis di Schengen e alle misure relative al regolamento Dublino e a Eurodac che partecipi a un determinato sistema IT su larga scala nomina un membro in seno al gruppo consultivo relativo a quel sistema IT su larga scala.</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Europol, Eurojust e l'Agenzia europea della guardia di frontiera e costiera possono nominare un rappresentante ciascuno in seno al gruppo consultivo SIS II.</div>\n</div>"], [null, "<p class=\"norm\">Europol può nominare un rappresentante in seno ai gruppi consultivi VIS ed Eurodac ed EES-ETIAS.</p>"], [null, "<p class=\"norm\">L'Agenzia europea della guardia di frontiera e costiera può nominare anche un rappresentante in seno al gruppo consultivo EES-ETIAS. Eurojust, Europol e la Procura europea possono nominare ciascuno un rappresentante in seno al gruppo consultivo ECRIS-TCN.</p>"], [null, "<p class=\"norm\">Europol, Eurojust e l'Agenzia europea della guardia di frontiera e costiera possono nominare un rappresentante ciascuno in seno al gruppo consultivo sull'interoperabilità.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">I membri del consiglio di amministrazione e i loro supplenti non sono membri di nessun gruppo consultivo. Il direttore esecutivo o un suo rappresentante può presenziare a tutte le riunioni dei gruppi consultivi in qualità di osservatore.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">I gruppi consultivi cooperano tra di loro ove necessario. Le procedure per il funzionamento e la cooperazione dei gruppi consultivi sono stabilite nel regolamento interno dell’Agenzia.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Quando preparano un parere, i membri di ogni gruppo consultivo si adoperano per giungere a un consenso. Se tale consenso non è raggiunto, si considera che il parere del gruppo consultivo rispecchi la posizione motivata della maggioranza dei membri. Sono messe a verbale anche la posizione o le posizioni di minoranza motivate. L’articolo 23, paragrafi 3 e 5, si applica di conseguenza. I membri che rappresentano i paesi associati all’attuazione, all’applicazione e allo sviluppo dell’acquis di Schengen e alle misure relative al regolamento Dublino e a Eurodac possono esprimere pareri in merito alle questioni sulle quali non hanno diritto di voto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro e ciascun paese associato all’attuazione, all’applicazione e allo sviluppo dell’acquis di Schengen e alle misure relative al regolamento Dublino e a Eurodac facilitano le attività dei gruppi consultivi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">L’articolo 21 si applica alla presidenza dei gruppi consultivi, <span class=\"italics\">mutatis mutandis</span>.</div>\n</div>"]]}, "28": {"label": "Articolo 28", "heading": "Personale", "anchor": "art_28", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Al personale dell’Agenzia, compreso il direttore esecutivo, si applicano lo statuto dei funzionari e le regole adottate di comune accordo dalle istituzioni dell’Unione per l’applicazione di detto statuto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ai fini dell’applicazione dello statuto l’Agenzia è considerata un’agenzia ai sensi dell’articolo 1 <span class=\"italics\">bis</span>, paragrafo 2, dello statuto dei funzionari.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il personale dell’Agenzia è composto di funzionari e agenti temporanei e contrattuali. Il consiglio di amministrazione dà il proprio assenso su base annuale nel caso di contratti che il direttore esecutivo intende rinnovare qualora, a seguito del rinnovo, diventino contratti a tempo indeterminato in base al regime applicabile agli altri agenti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L’Agenzia non assume personale interinale per svolgere mansioni finanziarie considerate sensibili.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">La Commissione e gli Stati membri possono distaccare temporaneamente funzionari o esperti nazionali presso l’Agenzia. Il consiglio di amministrazione adotta una decisione che stabilisce le norme relative al distacco di esperti nazionali presso l’Agenzia.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Fatto salvo l’articolo 17 dello statuto dei funzionari, l’Agenzia applica norme adeguate in materia di segreto professionale o altri obblighi di riservatezza equivalenti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Il consiglio di amministrazione, di concerto con la Commissione, adotta le necessarie disposizioni di esecuzione di cui all’articolo 110 dello statuto dei funzionari.</div>\n</div>"]]}, "29": {"label": "Articolo 29", "heading": "Interesse pubblico", "anchor": "art_29", "frags": [[null, "<p class=\"norm\">I membri del consiglio di amministrazione, il direttore esecutivo, il vicedirettore esecutivo e i membri dei gruppi consultivi si impegnano ad agire nell’interesse pubblico. A tal fine, emettono pubblicamente ogni anno una dichiarazione scritta d’impegno, che è pubblicata nel sito web dell’Agenzia.</p>"], [null, "<p class=\"norm\">L’elenco dei membri del consiglio di amministrazione e dei membri dei gruppi consultivi è pubblicato nel sito web dell’Agenzia.</p>"]]}, "30": {"label": "Articolo 30", "heading": "Accordo relativo alla sede e accordi relativi ai siti tecnici", "anchor": "art_30", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le necessarie disposizioni relative all’insediamento dell’Agenzia negli Stati membri ospitanti e alle strutture che tali Stati membri devono mettere a disposizione, così come le norme specifiche applicabili negli Stati membri ospitanti ai membri del consiglio d’amministrazione, al direttore esecutivo, agli altri membri del personale dell’Agenzia e ai loro familiari, sono fissate nell’accordo sulla sede dell’Agenzia e negli accordi sui siti tecnici. Tali accordi sono conclusi fra l’Agenzia e gli Stati membri ospitanti, previa approvazione del consiglio di amministrazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri che ospitano l’Agenzia garantiscono le condizioni necessarie per il buon funzionamento dell’Agenzia, offrendo anche, fra l’altro, una scolarizzazione multilingue e a orientamento europeo e collegamenti di trasporto adeguati.</div>\n</div>"]]}, "31": {"label": "Articolo 31", "heading": "Privilegi e immunità", "anchor": "art_31", "frags": [[null, "<p class=\"norm\">All’Agenzia si applica il protocollo sui privilegi e sulle immunità dell’Unione europea.</p>"]]}, "32": {"label": "Articolo 32", "heading": "Responsabilità civile", "anchor": "art_32", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La responsabilità contrattuale dell’Agenzia è disciplinata dal diritto applicabile al contratto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Corte di giustizia dell’Unione europea è competente a giudicare in virtù di clausole compromissorie contenute nel contratto concluso dall’Agenzia.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">In materia di responsabilità extracontrattuale l’Agenzia risarcisce, secondo i principi generali comuni agli ordinamenti degli Stati membri, i danni causati dai suoi servizi o dal suo personale nell’esercizio delle loro funzioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Corte di giustizia dell’Unione europea è competente a pronunciarsi sulle controversie relative al risarcimento dei danni di cui al paragrafo 3.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">La responsabilità personale dei membri del personale dell’Agenzia nei confronti dell’Agenzia è disciplinata dalle disposizioni loro applicabili dello statuto dei funzionari o del regime relativo agli altri agenti.</div>\n</div>"]]}, "33": {"label": "Articolo 33", "heading": "Regime linguistico", "anchor": "art_33", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il regolamento n. 1 del Consiglio (\n<span class=\"superscript\">14</span>\n) si applica all’Agenzia.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Fatte salve le decisioni adottate in base all’articolo 342 TFUE, il documento unico di programmazione di cui all’articolo 19, paragrafo 1, lettera r), e la relazione annuale di attività di cui all’articolo 19, paragrafo 1, lettera t), sono redatti in tutte le lingue ufficiali delle istituzioni dell’Unione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Fatti salvi gli obblighi di cui ai paragrafi 1 e 2, il consiglio di amministrazione può adottare una decisione sulle lingue di lavoro.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">I servizi di traduzione necessari per il funzionamento dell’Agenzia sono forniti dal Centro di traduzione degli organismi dell’Unione europea.</div>\n</div>"]]}, "34": {"label": "Articolo 34", "heading": "Trasparenza e comunicazione", "anchor": "art_34", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ai documenti detenuti dall’Agenzia si applica il regolamento (CE) n. 1049/2001.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il consiglio di amministrazione adotta senza ritardo le modalità di applicazione del regolamento (CE) n. 1049/2001 in base a una proposta del direttore esecutivo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le decisioni adottate dall’Agenzia ai sensi dell’articolo 8 del regolamento (CE) n. 1049/2001 possono costituire oggetto di denuncia presso il Mediatore europeo o di ricorso dinanzi alla Corte di giustizia dell’Unione europea alle condizioni, rispettivamente, di cui agli articoli 228 e 263 TFUE.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L’Agenzia comunica secondo quanto previsto dagli atti giuridici dell’Unione che disciplinano lo sviluppo, l’istituzione, l’esercizio e l’uso dei sistemi IT su larga scala e può svolgere attività di comunicazione di propria iniziativa nelle materie di sua competenza. L’Agenzia assicura in particolare che, oltre alle pubblicazioni specificate all’articolo 19, paragrafo 1, lettere r), t), ii), jj), kk) e ll), e all’articolo 47, paragrafo 9, il pubblico e qualsiasi parte interessata ricevano prontamente informazioni obiettive, accurate, affidabili, complete e di facile comprensione sull’attività da essa svolta. L’assegnazione di risorse alle attività di comunicazione non reca pregiudizio all’assolvimento effettivo dei compiti dell’Agenzia di cui agli articoli da 3 a 16. Le attività di comunicazione sono svolte in conformità dei pertinenti piani di comunicazione e divulgazione adottati dal consiglio di amministrazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Qualsiasi persona fisica o giuridica ha il diritto di rivolgersi per iscritto all’Agenzia in una delle lingue ufficiali dell’Unione. La persona interessata ha diritto di ricevere una risposta nella medesima lingua.</div>\n</div>"]]}, "35": {"label": "Articolo 35", "heading": "Protezione dei dati", "anchor": "art_35", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il trattamento dei dati personali da parte dell’Agenzia è soggetto al regolamento (UE) 2018/1725.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il consiglio di amministrazione adotta le misure di applicazione del regolamento (UE) 2018/1725 da parte dell’Agenzia, comprese le misure relative al responsabile della protezione dei dati. Tali modalità sono adottate previa consultazione del Garante europeo della protezione dei dati.</div>\n</div>"]]}, "36": {"label": "Articolo 36", "heading": "Finalità del trattamento dei dati personali", "anchor": "art_36", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’Agenzia può trattare i dati personali solo per i seguenti scopi:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ove necessario per lo svolgimento dei compiti di gestione operativa dei sistemi IT su larga scala ad essa affidati ai sensi del diritto dell’Unione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ove necessario per i suoi compiti amministrativi.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">In caso di trattamento di dati personali da parte dell’Agenzia per il fine previsto al paragrafo 1, lettera a), del presente articolo, si applica il regolamento (UE) 2018/1725, fatte salve le disposizioni specifiche in materia di protezione e sicurezza dei dati degli atti giuridici dell’Unione che disciplinano lo sviluppo, l’istituzione, l’esercizio e l’uso dei sistemi.</div>\n</div>"]]}, "37": {"label": "Articolo 37", "heading": "Norme di sicurezza per la protezione delle informazioni classificate e delle informazioni sensibili non classificate", "anchor": "art_37", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’Agenzia adotta le norme di sicurezza sulla base dei principi e delle regole stabiliti nelle norme di sicurezza della Commissione per la protezione delle informazioni classificate dell’Unione europea (ICUE) e delle informazioni sensibili non classificate, tra cui le disposizioni relative allo scambio con paesi terzi, al trattamento e alla conservazione di tali informazioni stabilite nelle decisioni (UE, Euratom) 2015/443 (\n<span class=\"superscript\">15</span>\n) e 2015/444 della Commissione (\n<span class=\"superscript\">16</span>\n). Qualsiasi accordo amministrativo sullo scambio di informazioni classificate con le autorità competenti di un paese terzo o, in assenza di tale accordo, qualsiasi comunicazione eccezionale ad hoc di ICUE a tali autorità devono essere approvati dalla Commissione in via preliminare.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il consiglio di amministrazione adotta le norme di sicurezza di cui al paragrafo 1 del presente articolo previa approvazione della Commissione. L’Agenzia può adottare tutte le misure necessarie per agevolare lo scambio, con la Commissione e gli Stati membri e, se del caso, con le pertinenti agenzie dell’Unione, di informazioni utili all’assolvimento dei suoi compiti. L’Agenzia sviluppa e gestisce un sistema informativo che permette di scambiare informazioni classificate con la Commissione, gli Stati membri e le pertinenti agenzie dell’Unione conformemente alla decisione (UE, Euratom) 2015/444. Il consiglio di amministrazione decide, conformemente all’articolo 2 e all’articolo 19, paragrafo 1, lettera z), la struttura interna dell’Agenzia necessaria ai fini del rispetto degli appropriati principi di sicurezza.</div>\n</div>"]]}, "38": {"label": "Articolo 38", "heading": "Sicurezza dell’Agenzia", "anchor": "art_38", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’Agenzia è responsabile della sicurezza e del mantenimento dell’ordine negli edifici, nei locali e sui terreni da essa utilizzati. L’Agenzia applica i principi di sicurezza e le pertinenti disposizioni degli atti giuridici dell’Unione che disciplinano lo sviluppo, l’istituzione, l’esercizio e l’uso dei sistemi IT su larga scala.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri ospitanti prendono tutte le misure efficaci e adeguate per mantenere l’ordine e la sicurezza nelle immediate vicinanze degli edifici, dei locali e dei terreni utilizzati dall’Agenzia e forniscono a quest’ultima una protezione adeguata conformemente all’accordo sulla sede dell’Agenzia e agli accordi relativi ai siti tecnici e di riserva, garantendo nel contempo il libero accesso delle persone autorizzate dall’Agenzia a tali edifici, locali e terreni.</div>\n</div>"]]}, "39": {"label": "Articolo 39", "heading": "Valutazione", "anchor": "art_39", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Entro il 12 dicembre 2023 e in seguito ogni cinque anni, la Commissione, dopo aver consultato il consiglio di amministrazione, valuta, in base ai propri orientamenti, le prestazioni dell’Agenzia in relazione agli obiettivi, al mandato, all’ubicazione e ai compiti stabiliti per essa. Oltre all’applicazione del presente regolamento, tale valutazione esamina come e in che misura l’Agenzia contribuisca effettivamente alla gestione operativa dei sistemi IT su larga scala e all’instaurazione a livello di Unione di un ambiente IT coordinato, efficiente in termini di costi e coerente nello spazio di libertà, sicurezza e giustizia. Tale valutazione esamina in particolare l’eventuale necessità di modificare il mandato dell’Agenzia e le conseguenze finanziarie di tale eventuale modifica. Il consiglio di amministrazione può formulare raccomandazioni alla Commissione in merito a modifiche del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione, se ritiene che il mantenimento dell’Agenzia non sia più giustificato rispetto agli obiettivi, al mandato e ai compiti che le sono stati assegnati, può proporre di modificare opportunamente o di abrogare il presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione riferisce le conclusioni della valutazione di cui al paragrafo 1 al Parlamento europeo, al Consiglio e al consiglio di amministrazione. I risultati della valutazione sono resi pubblici.</div>\n</div>"]]}, "40": {"label": "Articolo 40", "heading": "Indagini amministrative", "anchor": "art_40", "frags": [[null, "<p class=\"norm\">Le attività dell’Agenzia sono soggette alle indagini del Mediatore europeo in conformità dell’articolo 228 TFUE.</p>"]]}, "41": {"label": "Articolo 41", "heading": "Cooperazione con le istituzioni, gli organi e gli organismi dell’Unione", "anchor": "art_41", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Nelle materie contemplate dal presente regolamento l’Agenzia collabora con la Commissione, le altre istituzioni dell’Unione e gli altri organi e organismi dell’Unione, specialmente quelli istituiti nello spazio di libertà, sicurezza e giustizia, in particolare l’Agenzia dell’Unione europea per i diritti fondamentali per assicurare, tra l’altro, il coordinamento, realizzare risparmi sul piano finanziario, evitare duplicazioni e promuovere sinergie e complementarità nelle loro rispettive attività.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’Agenzia coopera con la Commissione nell’ambito di un accordo di collaborazione che stabilisce le modalità operative.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ove opportuno, l’Agenzia consulta e dà seguito alle raccomandazioni dell’Agenzia europea per la sicurezza delle reti e dell’informazione concernenti la sicurezza delle reti e dell’informazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La cooperazione con gli organi e gli organismi dell’Unione rientra nel quadro degli accordi di collaborazione. Il consiglio di amministrazione autorizza tali accordi di collaborazione, tenendo conto del parere della Commissione. Se l’Agenzia non si conforma al parere della Commissione, presenta le motivazioni di tale decisione. Gli accordi di collaborazione possono prevedere la condivisione dei servizi tra le agenzie, se del caso, sulla base della prossimità geografica o degli ambiti politici, nei limiti dei rispettivi mandati e fatti salvi i rispettivi compiti principali. Tali accordi di collaborazione possono stabilire un meccanismo di recupero dei costi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Le istituzioni, gli organi e gli organismi dell’Unione usano le informazioni ricevute dall’Agenzia esclusivamente entro i limiti delle loro competenze e fintanto che rispettino i diritti fondamentali, compresi gli obblighi di protezione dei dati. La trasmissione ulteriore o ogni altra comunicazione di dati personali trattati dall’Agenzia a istituzioni, organi e organismi dell’Unione sono soggette ad accordi di collaborazione specifici riguardanti lo scambio di dati personali e alla previa approvazione del Garante europeo della protezione dei dati. Qualsiasi trasferimento di dati personali da parte dell’Agenzia deve rispettare gli articoli 35 e 36. Per quanto riguarda il trattamento delle informazioni classificate, tali accordi di collaborazione prevedono che l’istituzione, l’organo o l’organismo dell’Unione rispetti regole e norme di sicurezza equivalenti a quelle applicate dall’Agenzia.</div>\n</div>"]]}, "42": {"label": "Articolo 42", "heading": "Partecipazione dei paesi associati all’attuazione, all’applicazione e allo sviluppo dell’acquis di Schengen e alle misure relative al regolamento di Dublino e a Eurodac", "anchor": "art_42", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’Agenzia è aperta alla partecipazione dei paesi che hanno concluso con l’Unione accordi riguardanti la loro associazione all’attuazione, all’applicazione e allo sviluppo dell’acquis di Schengen e alle misure relative al regolamento Dublino e a Eurodac.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Conformemente alle pertinenti disposizioni degli accordi di cui al paragrafo 1, sono concluse intese per specificare, in particolare, la natura, la portata e le regole dettagliate di partecipazione ai lavori dell’Agenzia dei paesi terzi di cui al paragrafo 1, comprese le disposizioni sui contributi finanziari, sul personale e sui diritti di voto.</div>\n</div>"]]}, "43": {"label": "Articolo 43", "heading": "Cooperazione con organizzazioni internazionali e altri organismi competenti", "anchor": "art_43", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ove previsto da un atto giuridico dell’Unione, nella misura in cui ciò sia necessario per lo svolgimento dei suoi compiti, l’Agenzia può, mediante la conclusione di accordi di collaborazione, instaurare e mantenere relazioni con organizzazioni internazionali e con i relativi organi subordinati, disciplinati dal diritto pubblico internazionale, o con altri soggetti o organismi competenti istituiti da, o sulla base di, un accordo tra due o più Stati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Conformemente al paragrafo 1, possono essere conclusi accordi di collaborazione che specifichino, in particolare, l’ambito, la natura, la finalità e la portata di tale cooperazione. Tali accordi di collaborazione possono essere conclusi solo con l’autorizzazione del consiglio di amministrazione e previa approvazione dalla Commissione.</div>\n</div>"]]}, "44": {"label": "Articolo 44", "heading": "Documento unico di programmazione", "anchor": "art_44", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ogni anno il direttore esecutivo predispone, tenuto conto degli orientamenti stabiliti della Commissione, un progetto di documento unico di programmazione per l’esercizio successivo, secondo quanto previsto all’articolo 32 del regolamento delegato (UE) n. 1271/2013 e nella pertinente disposizione della regolamentazione finanziaria dell’Agenzia adottata ai sensi dell’articolo 49 del presente regolamento.</p>\n<p class=\"norm inline-element\">Il documento unico di programmazione contiene un programma pluriennale, un programma di lavoro annuale, nonché il bilancio e le informazioni sulle risorse proprie dell’Agenzia, come precisato nella regolamentazione finanziaria dell’Agenzia adottata ai sensi dell’articolo 49.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il consiglio di amministrazione adotta il progetto di documento unico di programmazione previa consultazione dei gruppi consultivi e lo trasmette al Parlamento europeo, al Consiglio e alla Commissione entro il 31 gennaio di ogni anno, corredato dell’eventuale versione aggiornata.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Entro il 30 novembre di ogni anno, il consiglio di amministrazione adotta, tenuto conto del parere della Commissione, il documento unico di programmazione a maggioranza dei due terzi dei membri aventi diritto di voto e secondo la procedura annuale di bilancio. Il consiglio di amministrazione provvede a che la versione definitiva del documento unico di programmazione sia trasmessa al Parlamento europeo, al Consiglio e alla Commissione e sia pubblicata.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il documento unico di programmazione diventa definitivo dopo l’approvazione definitiva del bilancio generale dell’Unione e, se necessario, è adeguato di conseguenza. Il documento unico di programmazione adottato è quindi trasmesso al Parlamento europeo, al Consiglio e alla Commissione e pubblicato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il programma di lavoro annuale per l’esercizio successivo comprende gli obiettivi dettagliati e i risultati attesi, compresi gli indicatori di prestazione. Contiene inoltre una descrizione delle azioni da finanziare e l’indicazione delle risorse finanziarie e umane assegnate a ogni azione, conformemente ai principi di formazione del bilancio per attività e gestione per attività. Il programma di lavoro annuale è coerente con il programma di lavoro pluriennale di cui al paragrafo 6. Indica chiaramente i compiti aggiunti, modificati o soppressi rispetto all’esercizio finanziario precedente. Quando all’Agenzia è assegnato un nuovo compito, il consiglio di amministrazione modifica il programma di lavoro annuale adottato. Le modifiche sostanziali del programma di lavoro annuale sono adottate con la stessa procedura di quella applicabile al programma di lavoro annuale iniziale. Il consiglio di amministrazione può delegare al direttore esecutivo il potere di apportare modifiche non sostanziali al programma di lavoro annuale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Il programma pluriennale definisce la programmazione strategica generale, compresi gli obiettivi, i risultati attesi e gli indicatori di risultato. Riporta inoltre la programmazione delle risorse, compresi il bilancio pluriennale e il personale. La programmazione delle risorse è aggiornata ogni anno. La programmazione strategica è aggiornata secondo necessità, in particolare per adattarla all’esito della valutazione di cui all’articolo 39.</div>\n</div>"]]}, "45": {"label": "Articolo 45", "heading": "Formazione del bilancio", "anchor": "art_45", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ogni anno il direttore esecutivo prepara, tenendo conto delle attività svolte dall’Agenzia, un progetto di dichiarazione dello stato di previsione delle entrate e delle spese dell’Agenzia per l’esercizio successivo, incluso un progetto di tabella dell’organico, e lo trasmette al consiglio di amministrazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Sulla base del progetto di stato di previsione delle entrate e delle spese dell’Agenzia predisposto dal direttore esecutivo, il consiglio di amministrazione adotta un progetto di stato di previsione delle entrate e delle spese dell’Agenzia per l’esercizio successivo, comprensivo di un progetto di tabella dell’organico. Entro il 31 gennaio di ogni anno il consiglio di amministrazione trasmette il progetto alla Commissione e ai paesi associati all’attuazione, all’applicazione e allo sviluppo dell’acquis di Schengen e alle misure relative al regolamento Dublino e a Eurodac come parte integrante del documento unico di programmazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione trasmette all’autorità di bilancio il progetto di stato di previsione unitamente al progetto preliminare di bilancio generale dell’Unione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Sulla base del progetto di stato di previsione, la Commissione iscrive nel progetto di bilancio generale dell’Unione le stime che ritiene necessarie per quanto concerne la tabella dell’organico e l’importo del contributo a carico del bilancio generale e le trasmette all’autorità di bilancio ai sensi degli articoli 313 e 314 TFUE.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">L’autorità di bilancio autorizza gli stanziamenti a titolo di contributo per l’Agenzia.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">L’autorità di bilancio adotta la tabella dell’organico per l’Agenzia.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Il consiglio di amministrazione adotta il bilancio dell’Agenzia. Il bilancio diventa definitivo dopo l’approvazione definitiva del bilancio generale dell’Unione. Se del caso, il bilancio dell’Agenzia è sottoposto agli opportuni adeguamenti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Qualsiasi modifica del bilancio dell’Agenzia, inclusa la tabella dell’organico, segue la medesima procedura applicabile alla determinazione del bilancio iniziale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Fatto salvo l’articolo 17, paragrafo 5, il consiglio d’amministrazione comunica al più presto all’autorità di bilancio l’intenzione di realizzare qualsiasi progetto che possa avere incidenze finanziarie significative per il finanziamento del bilancio, in particolare i progetti di natura immobiliare, quali la locazione o l’acquisto di edifici. Il consiglio d’amministrazione ne informa la Commissione. Qualora uno dei due rami dell’autorità di bilancio intenda formulare un parere, notifica al consiglio di amministrazione, entro due settimane dal ricevimento dell’informazione relativa al progetto, l’intenzione di formulare tale parere. In mancanza di risposta, l’Agenzia può procedere con l’operazione prevista. Il regolamento delegato (UE) n. 1271/2013 si applica ai progetti riguardanti gli immobili che possono avere implicazioni significative per il bilancio dell’Agenzia.</div>\n</div>"]]}, "46": {"label": "Articolo 46", "heading": "Struttura del bilancio", "anchor": "art_46", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Tutte le entrate e le spese dell’Agenzia formano oggetto di previsioni per ciascun esercizio finanziario, che coincide con l’anno civile, e sono iscritte nel bilancio dell’Agenzia.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le entrate e le spese iscritte nel bilancio dell’Agenzia risultano in pareggio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Fatti salvi altri tipi di risorse, le entrate dell’Agenzia comprendono:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un contributo dell’Unione iscritto nel bilancio generale dell’Unione (sezione «Commissione»);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un contributo dei paesi associati all’attuazione, all’applicazione e allo sviluppo dell’acquis di Schengen e alle misure relative al regolamento Dublino e a Eurodac che partecipano ai lavori dell’Agenzia, secondo quanto previsto nei rispettivi accordi di associazione e nelle intese di cui all’articolo 42 che ne specificano il contributo finanziario;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un finanziamento dell’Unione, sotto forma di accordi di delega a norma della regolamentazione finanziaria dell’Agenzia adottata ai sensi dell’articolo 49 e delle disposizioni dei pertinenti strumenti di sostegno delle politiche dell’Unione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">contributi erogati dagli Stati membri per i servizi loro offerti conformemente all’accordo di delega di cui all’articolo 16;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il recupero dei costi pagati dagli organi e dagli organismi dell’Unione per servizi loro forniti conformemente agli accordi di collaborazione di cui all’articolo 41; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli eventuali contributi finanziari volontari degli Stati membri.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le spese dell’Agenzia comprendono le retribuzioni del personale, le spese amministrative e di infrastruttura e le spese di esercizio.</div>\n</div>"]]}, "47": {"label": "Articolo 47", "heading": "Esecuzione e controllo del bilancio", "anchor": "art_47", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il direttore esecutivo esegue il bilancio dell’Agenzia.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il direttore esecutivo trasmette ogni anno all’autorità di bilancio qualsiasi informazione rilevante in relazione ai risultati delle procedure di valutazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Entro il 1<span class=\"superscript\">o</span> marzo dell’esercizio finanziario N+1, il contabile dell’Agenzia comunica i conti provvisori dell’esercizio N al contabile della Commissione e alla Corte dei conti. Il contabile della Commissione procede al consolidamento dei conti provvisori delle istituzioni e degli organismi decentrati a norma dell’articolo 245 del regolamento (UE, Euratom) 2018/1046.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Entro il 31 marzo dell’anno N+1 il direttore esecutivo trasmette al Parlamento europeo, al Consiglio, alla Commissione e alla Corte dei conti una relazione sulla gestione finanziaria e di bilancio per l’anno N.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Entro il 31 marzo dell’anno N+1 il contabile della Commissione trasmette alla Corte dei conti i conti provvisori dell’Agenzia per l’anno N, consolidati con i conti della Commissione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Al ricevimento delle osservazioni della Corte dei conti sui conti provvisori dell’Agenzia, ai sensi dell’articolo 246 del regolamento (UE, Euratom) 2018/1046, il direttore esecutivo stabilisce i conti definitivi dell’agenzia sotto la propria responsabilità e li trasmette al consiglio di amministrazione per parere.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Il consiglio di amministrazione formula un parere sui conti definitivi dell’Agenzia per l’anno N.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Entro il 1<span class=\"superscript\">o</span> luglio dell’anno N+1 il direttore esecutivo trasmette i conti definitivi, corredati del parere del consiglio di amministrazione, al Parlamento europeo, al Consiglio, alla Commissione, alla Corte dei conti e ai paesi associati all’attuazione, all’applicazione e allo sviluppo dell’acquis di Schengen e alle misure relative al regolamento Dublino e a Eurodac.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Entro il 15 novembre dell’anno N+1 i conti definitivi per l’anno N sono pubblicati nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span>.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">10.  </span>\n<div class=\"norm inline-element\">Entro il 30 settembre dell’anno N+1il direttore esecutivo invia alla Corte dei conti una risposta alle osservazioni. Il direttore esecutivo trasmette tale risposta anche al consiglio di amministrazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">11.  </span>\n<div class=\"norm inline-element\">Il direttore esecutivo presenta al Parlamento europeo, su richiesta di quest’ultimo e a norma dell’articolo 261, paragrafo 3, del regolamento (UE, Euratom) 2018/1046, tutte le informazioni necessarie per il corretto svolgimento della procedura di discarico per l’esercizio N.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">12.  </span>\n<div class=\"norm inline-element\">Entro il 15 maggio dell’anno N+2 il Parlamento europeo, su raccomandazione del Consiglio che delibera a maggioranza qualificata, concede il discarico al direttore esecutivo per l’esecuzione del bilancio dell’esercizio N.</div>\n</div>"]]}, "48": {"label": "Articolo 48", "heading": "Prevenzione dei conflitti di interesse", "anchor": "art_48", "frags": [[null, "<p class=\"norm\">L’Agenzia adotta norme interne che impongono ai membri del suo consiglio di amministrazione, dei suoi gruppi consultivi e del suo personale di evitare, durante il rapporto di impiego o il mandato, qualsiasi situazione che possa causare un conflitto di interesse e di segnalare tali situazioni. Tali norme interne sono pubblicate sul sito Internet dell’Agenzia.</p>"]]}, "49": {"label": "Articolo 49", "heading": "Regolamentazione finanziaria", "anchor": "art_49", "frags": [[null, "<p class=\"norm\">La regolamentazione finanziaria applicabile all’Agenzia è adottata dal consiglio di amministrazione previa consultazione della Commissione. Si discosta dal regolamento delegato (UE) n. 1271/2013 solo per esigenze specifiche di funzionamento dell’Agenzia e previo accordo della Commissione.</p>"]]}, "50": {"label": "Articolo 50", "heading": "Lotta antifrode", "anchor": "art_50", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ai fini della lotta contro la frode, la corruzione e altri atti illeciti si applicano il regolamento (UE, Euratom) n. 883/2013 e il regolamento (UE) 2017/1939.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’Agenzia aderisce all’accordo interistituzionale del 25 maggio 1999 relativo alle indagini interne svolte dall’OLAF e adotta, senza ritardo, le opportune disposizioni applicabili a tutti i dipendenti dell’Agenzia utilizzando i modelli riportati nell’allegato di tale accordo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Corte dei conti ha il potere di verifica, esercitabile su documenti e mediante ispezioni sul posto, su tutti i beneficiari di sovvenzioni, i contraenti e i subcontraenti che hanno beneficiato di fondi dell’Unione tramite l’Agenzia.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L’OLAF può effettuare indagini, inclusi controlli e ispezioni in loco secondo le disposizioni e le procedure stabilite dal regolamento (UE, Euratom) n. 883/2013 e dal regolamento (Euratom, CE) n. 2185/96 del Consiglio (\n<span class=\"superscript\">17</span>\n), per accertare eventuali frodi, casi di corruzione o altre attività illecite lesive degli interessi finanziari dell’Unione in relazione a una sovvenzione o a un contratto finanziati dall’Agenzia.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Fatti salvi i paragrafi 1, 2, 3 e 4, i contratti, le convenzioni di sovvenzione e le decisioni di sovvenzione dell’Agenzia contengono disposizioni che autorizzano esplicitamente la Corte dei conti, l’OLAF e l’EPPO a procedere a tali controlli e indagini secondo le loro rispettive competenze.</div>\n</div>"]]}, "51": {"label": "Articolo 51", "heading": "Modifica del regolamento (CE) n. 1987/2006", "anchor": "art_51", "frags": [[null, "<p class=\"norm\">All’articolo 15 del regolamento (CE) n. 1987/2006, i paragrafi 2 e 3 sono sostituiti dal seguente:</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">«2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’organo di gestione è responsabile di tutti i compiti connessi con l’infrastruttura di comunicazione, in particolare:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">controllo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sicurezza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">coordinamento dei rapporti tra gli Stati membri e il gestore;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">compiti relativi all’esecuzione del bilancio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">acquisizione e rinnovo; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">aspetti contrattuali.».</p>\n</div>\n</div>\n</div>\n</div>"]]}, "52": {"label": "Articolo 52", "heading": "Modifica della decisione 2007/533/GAI", "anchor": "art_52", "frags": [[null, "<p class=\"norm\">All’articolo 15 della decisione 2007/533/GAI, i paragrafi 2 e 3 sono sostituiti dai seguenti:</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">«2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’organo di gestione è responsabile altresì di tutti i compiti connessi con l’infrastruttura di comunicazione, in particolare:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">controllo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sicurezza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">coordinamento dei rapporti tra gli Stati membri e il gestore;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">compiti relativi all’esecuzione del bilancio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">acquisizione e rinnovo; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">aspetti contrattuali.».</p>\n</div>\n</div>\n</div>\n</div>"]]}, "53": {"label": "Articolo 53", "heading": "Successione legale", "anchor": "art_53", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’Agenzia istituita con il presente regolamento subentra in tutti i contratti conclusi, nelle passività a carico e nelle proprietà acquisite dall’Agenzia europea per la gestione operativa dei sistemi IT su larga scala nello spazio di libertà, sicurezza e giustizia istituita dal regolamento (UE) n. 1077/2011.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il presente regolamento non pregiudica l’efficacia giuridica degli accordi, degli accordi di collaborazione e dei memorandum d’intesa conclusi dall’Agenzia istituita dal regolamento (UE) 1077/2011, fatte salve eventuali modifiche resesi necessarie in virtù del presente regolamento.</div>\n</div>"]]}, "54": {"label": "Articolo 54", "heading": "Disposizioni transitorie relative al consiglio di amministrazione e ai gruppi consultivi", "anchor": "art_54", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I membri, il presidente e il vicepresidente del consiglio di amministrazione, nominati rispettivamente sulla base degli articoli 13 e 14 del regolamento (UE) n. 1077/2011, continuano a esercitare le loro funzioni per la durata restante del loro mandato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I membri, i presidenti e i vicepresidenti dei gruppi consultivi nominati sulla base dell’articolo 19 del regolamento (UE) n. 1077/2011 continuano a esercitare le loro funzioni per la durata restante del loro mandato.</div>\n</div>"]]}, "55": {"label": "Articolo 55", "heading": "Mantenimento in vigore delle norme interne adottate dal consiglio di amministrazione", "anchor": "art_55", "frags": [[null, "<p class=\"norm\">Le norme interne e le misure adottate dal consiglio di amministrazione sulla base del regolamento (UE) n. 1077/2011 rimangono in vigore dopo l’11 dicembre 2018, fatte salve eventuali modifiche che si rendono necessarie in virtù del presente regolamento.</p>"]]}, "56": {"label": "Articolo 56", "heading": "Disposizioni transitorie relative al direttore esecutivo", "anchor": "art_56", "frags": [[null, "<p class=\"norm\">Il direttore esecutivo dell’agenzia europea per la gestione operativa di sistemi IT su larga scala nello spazio di libertà, sicurezza e giustizia, nominato sulla base dell’articolo 18 del regolamento (UE) n. 1077/2011 assume, per la restante durata del suo mandato, le funzioni di direttore esecutivo dell’Agenzia ai sensi dell’articolo 24 del presente regolamento. Le altre condizioni contrattuali rimangono invariate. Se la decisione di proroga del mandato del direttore esecutivo a norma dell’articolo 18, paragrafo 4, del regolamento (UE) n. 1077/2011 è adottata prima dell’11 dicembre 2018, la durata del mandato è prorogata automaticamente fino al 31 ottobre 2022.</p>"]]}, "57": {"label": "Articolo 57", "heading": "Sostituzione e abrogazione", "anchor": "art_57", "frags": [[null, "<p class=\"norm\">Il regolamento (UE) n. 1077/2011 è sostituito per gli Stati membri vincolati dal presente regolamento.</p>"], [null, "<p class=\"norm\">Pertanto, il regolamento (UE) n. 1077/2011 è abrogato.</p>"], [null, "<p class=\"norm\">Con riguardo agli Stati membri vincolati dal presente regolamento, i riferimenti al regolamento abrogato si intendono fatti al presente regolamento e si leggono secondo la tavola di concordanza di cui all’allegato del presente regolamento.</p>"]]}, "58": {"label": "Articolo 58", "heading": "Entrata in vigore e applicabilità", "anchor": "art_58", "frags": [[null, "<p class=\"norm\">Il presente regolamento entra in vigore il ventesimo giorno successivo alla pubblicazione nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span>.</p>"], [null, "<p class=\"norm\">Il presente regolamento si applica a decorrere dall’11 dicembre 2018. Tuttavia, l’articolo 19, paragrafo 1, lettera x), l’articolo 24, paragrafo 3, lettere h) e i), e l’articolo 50, paragrafo 5, del presente regolamento, nella misura in cui si riferiscono all’EPPO, e l’articolo 50, paragrafo 1, del presente regolamento, nella misura in cui si riferisce al regolamento (UE) 2017/1939, si applicano a decorrere dalla data stabilita dalla decisione della Commissione di cui all’articolo 120, paragrafo 2, secondo comma, del regolamento (UE) 2017/1939.</p>"]]}}, "recitals": {}};